import{c as e,S as a,j as i,m as l}from"./chunks/framework.Dj4pu3XH.js";const y=JSON.parse('{"title":"Capability parity with gllvmTMB","description":"","frontmatter":{},"headers":[],"relativePath":"gllvmtmb-parity.md","filePath":"gllvmtmb-parity.md","lastUpdated":null}'),r={name:"gllvmtmb-parity.md"};function d(n,t,s,o,g,c){return a(),i("div",null,[...t[0]||(t[0]=[l('<h1 id="Capability-parity-with-gllvmTMB" tabindex="-1">Capability parity with gllvmTMB <a class="header-anchor" href="#Capability-parity-with-gllvmTMB" aria-label="Permalink to &quot;Capability parity with gllvmTMB {#Capability-parity-with-gllvmTMB}&quot;">​</a></h1><p>GLLVM.jl is a from-scratch Julia twin of R&#39;s <code>gllvmTMB</code>, built for fitting speed at moderate-to-large species counts while reproducing point estimates and likelihoods to machine precision on the shared Gaussian + phylogenetic path. This page is the live <strong>catch-up scoreboard</strong> — where GLLVM.jl stands against the <code>gllvmTMB</code> feature set. For <em>speed</em> comparisons see <a href="./comparison">Comparison</a> and <a href="./benchmarks">Benchmarks</a>.</p><p>Legend: ✅ available · 🔨 in progress · ⬜ planned · ⚡ GLLVM.jl advantage.</p><h2 id="Response-families" tabindex="-1">Response families <a class="header-anchor" href="#Response-families" aria-label="Permalink to &quot;Response families {#Response-families}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Family</th><th style="text-align:center;">GLLVM.jl</th><th style="text-align:right;">Notes</th></tr></thead><tbody><tr><td style="text-align:right;">Gaussian</td><td style="text-align:center;">✅</td><td style="text-align:right;">closed-form marginal</td></tr><tr><td style="text-align:right;">Binomial (Bernoulli / counts)</td><td style="text-align:center;">✅</td><td style="text-align:right;">logit / probit / cloglog</td></tr><tr><td style="text-align:right;">Poisson</td><td style="text-align:center;">✅</td><td style="text-align:right;">log link</td></tr><tr><td style="text-align:right;">Negative binomial</td><td style="text-align:center;">✅</td><td style="text-align:right;">dispersion <code>r</code> jointly estimated</td></tr><tr><td style="text-align:right;">Beta</td><td style="text-align:center;">✅</td><td style="text-align:right;">precision <code>φ</code></td></tr><tr><td style="text-align:right;">Ordinal (cumulative logit)</td><td style="text-align:center;">✅</td><td style="text-align:right;">common ordered cutpoints</td></tr><tr><td style="text-align:right;">Gamma</td><td style="text-align:center;">✅</td><td style="text-align:right;">shape <code>α</code></td></tr><tr><td style="text-align:right;">Hurdle (Poisson / NB)</td><td style="text-align:center;">🔨</td><td style="text-align:right;">two-part substrate building</td></tr><tr><td style="text-align:right;">Zero-inflated (ZIP / ZINB)</td><td style="text-align:center;">🔨</td><td style="text-align:right;">two-part substrate building</td></tr><tr><td style="text-align:right;">Delta (lognormal / Gamma)</td><td style="text-align:center;">🔨</td><td style="text-align:right;">two-part substrate building</td></tr><tr><td style="text-align:right;">Tweedie · Exponential</td><td style="text-align:center;">⬜</td><td style="text-align:right;">planned (Exponential ⊂ Gamma)</td></tr></tbody></table><h2 id="Model-structure" tabindex="-1">Model structure <a class="header-anchor" href="#Model-structure" aria-label="Permalink to &quot;Model structure {#Model-structure}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Capability</th><th style="text-align:center;">GLLVM.jl</th><th style="text-align:right;">Notes</th></tr></thead><tbody><tr><td style="text-align:right;">Latent-variable ordination (loadings)</td><td style="text-align:center;">✅</td><td style="text-align:right;">any <code>K</code>; canonical SVD rotation</td></tr><tr><td style="text-align:right;">Fixed-effect covariates (<code>Xβ</code>)</td><td style="text-align:center;">✅ Gaussian · 🔨 non-Gaussian</td><td style="text-align:right;">adding <code>Xβ</code> to the Laplace path is a (c) prerequisite</td></tr><tr><td style="text-align:right;">Between / within (multilevel)</td><td style="text-align:center;">✅ Gaussian</td><td style="text-align:right;"><code>K_W</code> + per-trait diagonal</td></tr><tr><td style="text-align:right;">Phylogenetic random effect</td><td style="text-align:center;">✅ ⚡</td><td style="text-align:right;">fast <strong>O(p)</strong> sparse path, benchmarked to p = 10⁴</td></tr><tr><td style="text-align:right;">Animal model (relatedness / GRM)</td><td style="text-align:center;">✅ Gaussian</td><td style="text-align:right;"><code>relatedness_cov</code>, via the <code>Σ_phy</code> input</td></tr><tr><td style="text-align:right;">Spatial (Matérn / exponential)</td><td style="text-align:center;">✅ Gaussian</td><td style="text-align:right;"><code>spatial_cov</code>, via the <code>Σ_phy</code> input</td></tr><tr><td style="text-align:right;">Structured dependence × non-Gaussian</td><td style="text-align:center;">🔨</td><td style="text-align:right;">joint-Laplace substrate building (b)</td></tr><tr><td style="text-align:right;">Random slopes <code>(1 + x | g)</code></td><td style="text-align:center;">🔨</td><td style="text-align:right;">formula front-end (c)</td></tr></tbody></table><h2 id="Post-fit-and-inference" tabindex="-1">Post-fit &amp; inference <a class="header-anchor" href="#Post-fit-and-inference" aria-label="Permalink to &quot;Post-fit &amp; inference {#Post-fit-and-inference}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Capability</th><th style="text-align:center;">GLLVM.jl</th><th style="text-align:right;">Notes</th></tr></thead><tbody><tr><td style="text-align:right;"><code>getLV</code> / <code>getLoadings</code> / <code>rotation</code></td><td style="text-align:center;">✅</td><td style="text-align:right;">all families</td></tr><tr><td style="text-align:right;"><code>predict</code> / <code>fitted</code></td><td style="text-align:center;">✅</td><td style="text-align:right;">all families (ordinal adds <code>:prob</code> / <code>:class</code>)</td></tr><tr><td style="text-align:right;"><code>residuals</code> (Dunn–Smyth + Pearson)</td><td style="text-align:center;">✅</td><td style="text-align:right;">all families</td></tr><tr><td style="text-align:right;"><code>aic</code> / <code>bic</code> / <code>show</code></td><td style="text-align:center;">✅</td><td style="text-align:right;">all families</td></tr><tr><td style="text-align:right;">Σ_y / communality / correlation / phylo signal H²</td><td style="text-align:center;">✅ Gaussian</td><td style="text-align:right;">report-ready extractors</td></tr><tr><td style="text-align:right;">Confidence intervals (Wald / profile / bootstrap)</td><td style="text-align:center;">✅ Gaussian · ⬜ non-Gaussian</td><td style="text-align:right;">a genuine gap</td></tr><tr><td style="text-align:right;">Ordination biplot</td><td style="text-align:center;">✅</td><td style="text-align:right;"></td></tr></tbody></table><h2 id="Interface" tabindex="-1">Interface <a class="header-anchor" href="#Interface" aria-label="Permalink to &quot;Interface {#Interface}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Capability</th><th style="text-align:center;">GLLVM.jl</th><th style="text-align:right;">Notes</th></tr></thead><tbody><tr><td style="text-align:right;">Matrix-level fit API</td><td style="text-align:center;">✅</td><td style="text-align:right;"><code>fit_gllvm(Y; family, K, …)</code></td></tr><tr><td style="text-align:right;"><code>@formula</code> front-end (wide + long data)</td><td style="text-align:center;">🔨</td><td style="text-align:right;">gllvmTMB-parity grammar (c)</td></tr><tr><td style="text-align:right;"><code>traits()</code> / <code>phylo()</code> formula terms</td><td style="text-align:center;">🔨</td><td style="text-align:right;">custom StatsModels terms (c)</td></tr></tbody></table><h2 id="Performance-—-the-differentiator" tabindex="-1">Performance — the differentiator <a class="header-anchor" href="#Performance-—-the-differentiator" aria-label="Permalink to &quot;Performance — the differentiator {#Performance-—-the-differentiator}&quot;">​</a></h2><p>⚡ ~340× per-fit median speedup over R <code>gllvmTMB</code> on the Gaussian + phylogenetic path (with machine-precision agreement on estimates and likelihoods), and an O(p) phylogenetic gradient benchmarked to p = 10,000. The non-Gaussian fitters are moving from finite-difference to analytic / forward-mode AD gradients for further fit-time gains.</p><h2 id="Honest-gaps" tabindex="-1">Honest gaps <a class="header-anchor" href="#Honest-gaps" aria-label="Permalink to &quot;Honest gaps {#Honest-gaps}&quot;">​</a></h2><ul><li><p><strong>Confidence intervals for non-Gaussian families</strong> — not yet wired.</p></li><li><p><strong>Structured dependence (phylo / animal / spatial) with non-Gaussian responses</strong> — in design/build (b).</p></li><li><p><strong><code>@formula</code> interface and random slopes</strong> — in build (c).</p></li><li><p><strong>Tweedie / exponential families</strong> — planned.</p></li><li><p><strong>R bridge (<code>engine = &quot;julia&quot;</code>)</strong> — deferred (post-v1.0).</p></li></ul>',15)])])}const p=e(r,[["render",d]]);export{y as __pageData,p as default};
